update jst_points_account
set available_points = available_points - #{points},
    frozen_points = frozen_points + #{points},
    version = version + 1,
    update_by = #{updateBy},
    update_time = #{updateTime}
where account_id = #{accountId}
  and version = #{version}
  and available_points >= #{points}
  and del_flag = '0'

update jst_points_account
set frozen_points = frozen_points - #{points},
    total_spend = total_spend + #{points},
    version = version + 1,
    update_by = #{updateBy},
    update_time = #{updateTime}
where account_id = #{accountId}
  and version = #{version}
  and frozen_points >= #{points}
  and del_flag = '0'

update jst_points_account
set available_points = available_points + #{points},
    frozen_points = frozen_points - #{points},
    version = version + 1,
    update_by = #{updateBy},
    update_time = #{updateTime}
where account_id = #{accountId}
  and version = #{version}
  and frozen_points >= #{points}
  and del_flag = '0'

